     1→import type { Metadata } from 'next';
     2→import { GuestChannelView } from '@/components/channel/GuestChannelView';
     3→import { getServer } from '@/services/serverService';
     4→import { getChannel, ChannelVisibility } from '@/services/channelService';
     5→
     6→interface PageProps {
     7→  params: Promise<{ serverSlug: string; channelSlug: string }>;
     8→}
     9→
    10→export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
    11→  const { serverSlug, channelSlug } = await params;
    12→  const [server, channel] = await Promise.all([
    13→    getServer(serverSlug),
    14→    getChannel(serverSlug, channelSlug),
    15→  ]);
    16→
    17→  const channelName = channel?.name ?? channelSlug;
    18→  const serverName = server?.name ?? serverSlug;
    19→  const isIndexable = channel?.visibility === ChannelVisibility.PUBLIC_INDEXABLE;
    20→
    21→  return {
    22→    title: `${channelName} - ${serverName} | Harmony`,
    23→    robots: { index: isIndexable, follow: true },
    24→  };
    25→}
    26→
    27→export default async function GuestChannelPage({ params }: PageProps) {
    28→  const { serverSlug, channelSlug } = await params;
    29→  return <GuestChannelView serverSlug={serverSlug} channelSlug={channelSlug} />;
    30→}
