     1→/**
     2→ * Channel Component: GuestPromoBanner
     3→ * Non-intrusive sticky bottom banner encouraging guests to join Harmony.
     4→ * Dismiss state persists for the browser session via sessionStorage.
     5→ * Based on dev spec C1.4 GuestPromoBanner
     6→ */
     7→
     8→'use client';
     9→
    10→import { useState, useCallback, useSyncExternalStore } from 'react';
    11→import Link from 'next/link';
    12→import { usePathname } from 'next/navigation';
    13→import { useAuth } from '@/hooks/useAuth';
    14→
    15→const DISMISS_KEY = 'harmony_guest_banner_dismissed';
    16→
    17→function isDismissedInStorage(): boolean {
    18→  try {
    19→    return sessionStorage.getItem(DISMISS_KEY) === 'true';
    20→  } catch {
    21→    return false;
    22→  }
    23→}
    24→
    25→interface GuestPromoBannerProps {
    26→  serverName: string;
    27→  memberCount: number;
    28→}
    29→
    30→export function GuestPromoBanner({ serverName, memberCount }: GuestPromoBannerProps) {
    31→  const { isAuthenticated } = useAuth();
    32→  const pathname = usePathname();
    33→  // useSyncExternalStore with a server snapshot of `true` (hidden) prevents
    34→  // hydration mismatch: SSR and initial client render both produce null, then
    35→  // React reconciles with the real client snapshot after hydration — no
    36→  // setState-in-effect needed.
    37→  const storageDismissed = useSyncExternalStore(
    38→    () => () => {},       // sessionStorage has no change events
    39→    isDismissedInStorage, // client snapshot
    40→    () => true,           // server snapshot: always hidden
    41→  );
    42→
    43→  // Tracks in-memory dismiss for the current render cycle, covering the case
    44→  // where sessionStorage.setItem throws (private browsing, etc.).
    45→  const [manuallyDismissed, setManuallyDismissed] = useState(false);
    46→
    47→  const handleDismiss = useCallback(() => {
    48→    try {
    49→      sessionStorage.setItem(DISMISS_KEY, 'true');
    50→    } catch {
    51→      // sessionStorage unavailable — still dismiss in-memory
    52→    }
    53→    setManuallyDismissed(true);
    54→  }, []);
    55→
    56→  if (storageDismissed || manuallyDismissed || isAuthenticated) return null;
    57→
    58→  const returnUrl = encodeURIComponent(pathname);
    59→
    60→  return (
    61→    <aside
    62→      aria-label='Join server promotion'
    63→      className='sticky bottom-0 z-20 border-t border-[#2a2d31] bg-[#2f3136] px-4 py-3 shadow-lg'
    64→    >
    65→      <div className='mx-auto flex max-w-4xl items-center gap-3'>
    66→        {/* Server icon — first letter avatar */}
    67→        <div
    68→          className='flex h-9 w-9 shrink-0 items-center justify-center rounded-full bg-[#5865f2] text-sm font-bold text-white'
    69→          aria-hidden='true'
    70→        >
    71→          {serverName[0].toUpperCase()}
    72→        </div>
    73→
    74→        {/* Server info */}
    75→        <div className='min-w-0 flex-1'>
    76→          <p className='truncate text-sm font-semibold text-white'>{serverName}</p>
    77→          <p className='text-xs text-gray-400'>{memberCount.toLocaleString()} members</p>
    78→        </div>
    79→
    80→        {/* CTAs */}
    81→        <div className='flex shrink-0 items-center gap-2'>
    82→          <Link
    83→            href={`/auth/signup?returnUrl=${returnUrl}`}
    84→            className='inline-flex h-8 items-center justify-center rounded-md bg-[#5865f2] px-3 text-sm font-medium text-white transition-colors hover:bg-[#4752c4]'
    85→          >
    86→            <span className='hidden sm:inline'>Create Account</span>
    87→            <span className='sm:hidden'>Join</span>
    88→          </Link>
    89→          <Link
    90→            href={`/auth/login?returnUrl=${returnUrl}`}
    91→            className='inline-flex h-8 items-center justify-center rounded-md border border-white/20 bg-[#40444b] px-3 text-sm font-medium text-gray-200 transition-colors hover:bg-[#3d4148]'
    92→          >
    93→            Log In
    94→          </Link>
    95→          <button
    96→            type='button'
    97→            onClick={handleDismiss}
    98→            className='ml-1 rounded p-1 text-gray-400 transition-colors hover:bg-[#40444b] hover:text-white'
    99→            aria-label='Dismiss banner'
   100→          >
   101→            <svg
   102→              xmlns='http://www.w3.org/2000/svg'
   103→              width='16'
   104→              height='16'
   105→              viewBox='0 0 24 24'
   106→              fill='none'
   107→              stroke='currentColor'
   108→              strokeWidth='2'
   109→              strokeLinecap='round'
   110→              strokeLinejoin='round'
   111→              aria-hidden='true'
   112→              focusable='false'
   113→            >
   114→              <line x1='18' y1='6' x2='6' y2='18' />
   115→              <line x1='6' y1='6' x2='18' y2='18' />
   116→            </svg>
   117→          </button>
   118→        </div>
   119→      </div>
   120→    </aside>
   121→  );
   122→}
