     1→'use client';
     2→
     3→import { createContext, useState, useEffect, useCallback } from 'react';
     4→import type { ReactNode } from 'react';
     5→import type { User } from '@/types';
     6→import * as authService from '@/services/authService';
     7→import { setSessionCookie, clearSessionCookie } from '@/app/actions/session';
     8→
     9→// ─── Types ────────────────────────────────────────────────────────────────────
    10→
    11→export interface AuthContextValue {
    12→  user: User | null;
    13→  isAuthenticated: boolean;
    14→  isLoading: boolean;
    15→  login: (email: string, password: string) => Promise<void>;
    16→  register: (email: string, username: string, displayName: string, password: string) => Promise<void>;
    17→  logout: () => Promise<void>;
    18→  updateUser: (patch: Partial<Pick<User, 'displayName' | 'status'>>) => Promise<void>;
    19→  /**
    20→   * Returns true if the current user has admin-level access.
    21→   * Pass `serverOwnerId` to check ownership of a specific server — this is the
    22→   * reliable path since User.role is not populated from the backend.
    23→   * Without `serverOwnerId`, falls back to checking User.role (always 'member'
    24→   * until a global-role endpoint is added).
    25→   */
    26→  isAdmin: (serverOwnerId?: string) => boolean;
    27→}
    28→
    29→// ─── Context ──────────────────────────────────────────────────────────────────
    30→
    31→export const AuthContext = createContext<AuthContextValue | null>(null);
    32→
    33→// ─── Provider ─────────────────────────────────────────────────────────────────
    34→
    35→export function AuthProvider({ children }: { children: ReactNode }) {
    36→  const [user, setUser] = useState<User | null>(null);
    37→  const [isLoading, setIsLoading] = useState(true);
    38→
    39→  // On mount: try to restore session via the refresh token (if present).
    40→  // The api-client will transparently use the stored refresh token to get
    41→  // a fresh access token if needed. If a user is restored, also refresh the
    42→  // httpOnly middleware cookie so server-side route protection stays active.
    43→  useEffect(() => {
    44→    authService
    45→      .getCurrentUser()
    46→      .then(async restored => {
    47→        if (restored) {
    48→          setUser(restored);
    49→          // Re-set the httpOnly cookie so middleware can continue protecting
    50→          // routes without requiring a full re-login.
    51→          await setSessionCookie({ sub: restored.id, username: restored.username, role: restored.role });
    52→        }
    53→      })
    54→      .catch(() => {
    55→        // No valid session — stay logged out
    56→      })
    57→      .finally(() => setIsLoading(false));
    58→  }, []);
    59→
    60→  const login = useCallback(async (email: string, password: string) => {
    61→    const loggedInUser = await authService.login(email, password);
    62→    setUser(loggedInUser);
    63→    // Set httpOnly session cookie so middleware can protect routes server-side.
    64→    // When #113 lands with real JWT, this call is replaced by the backend
    65→    // setting the cookie via Set-Cookie on the /api/auth/login response.
    66→    await setSessionCookie({ sub: loggedInUser.id, username: loggedInUser.username, role: loggedInUser.role });
    67→  }, []);
    68→
    69→  const register = useCallback(
    70→    async (email: string, username: string, displayName: string, password: string) => {
    71→      const newUser = await authService.register(email, username, displayName, password);
    72→      setUser(newUser);
    73→      await setSessionCookie({ sub: newUser.id, username: newUser.username, role: newUser.role });
    74→    },
    75→    [],
    76→  );
    77→
    78→  const logout = useCallback(async () => {
    79→    await authService.logout();
    80→    setUser(null);
    81→    await clearSessionCookie();
    82→  }, []);
    83→
    84→  const updateUser = useCallback(
    85→    async (patch: Partial<Pick<User, 'displayName' | 'status'>>) => {
    86→      const updated = await authService.updateCurrentUser(patch);
    87→      setUser(updated);
    88→    },
    89→    [],
    90→  );
    91→
    92→  const isAdmin = useCallback((serverOwnerId?: string) => {
    93→    if (!user) return false;
    94→    if (serverOwnerId) return user.id === serverOwnerId;
    95→    return user.role === 'owner' || user.role === 'admin';
    96→  }, [user]);
    97→
    98→  const value: AuthContextValue = {
    99→    user,
   100→    isAuthenticated: user !== null,
   101→    isLoading,
   102→    login,
   103→    register,
   104→    logout,
   105→    updateUser,
   106→    isAdmin,
   107→  };
   108→
   109→  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
   110→}
