/**
 * User Settings Page (Issue #88)
 * Client component — Discord-style sidebar settings for the current user.
 * Sections: My Account (view + edit profile), Danger Zone (logout).
 */

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import Image from 'next/image';
import { useAuth } from '@/hooks/useAuth';
import { cn } from '@/lib/utils';
import type { UserStatus } from '@/types';
import { isChannelGuestAccessible } from '@/app/settings/actions';

// ─── Discord colour tokens ────────────────────────────────────────────────────

const BG = {
  base: 'bg-[#313338]',
  sidebar: 'bg-[#2f3136]',
  active: 'bg-[#3d4148]',
  input: 'bg-[#1e1f22]',
};

// ─── Status helpers ───────────────────────────────────────────────────────────

const STATUS_COLOR: Record<UserStatus, string> = {
  online: 'bg-green-500',
  idle: 'bg-yellow-400',
  dnd: 'bg-red-500',
  offline: 'bg-gray-400',
};

const STATUS_LABEL: Record<UserStatus, string> = {
  online: 'Online',
  idle: 'Idle',
  dnd: 'Do Not Disturb',
  offline: 'Offline',
};

const ALL_STATUSES: UserStatus[] = ['online', 'idle', 'dnd', 'offline'];

// ─── Sidebar sections ─────────────────────────────────────────────────────────

type Section = 'account' | 'logout';

const SECTIONS: { id: Section; label: string; danger?: boolean }[] = [
  { id: 'account', label: 'My Account' },
  { id: 'logout', label: 'Log Out', danger: true },

'use server';

import { getChannel, ChannelVisibility } from '@/services/channelService';

/**
 * Returns true if the channel at the given slugs is publicly accessible to
 * unauthenticated users (PUBLIC_INDEXABLE or PUBLIC_NO_INDEX). Returns false
 * for PRIVATE channels and channels that don't exist.
 *
 * Deliberately does NOT expose the raw ChannelVisibility enum to avoid
 * channel-existence probing by iterating slug combinations.
 */
export async function isChannelGuestAccessible(
  serverSlug: string,
  channelSlug: string,
): Promise<boolean> {
  const channel = await getChannel(serverSlug, channelSlug);
  if (!channel) return false;
  return channel.visibility !== ChannelVisibility.PRIVATE;
}

