// Simple mock server for testing issue #116 frontend integration
const http = require('http');

const mockServer = {
  id: 'server-001', name: 'Harmony HQ', slug: 'harmony-hq',
  iconUrl: null, description: 'The official Harmony server',
  memberCount: 1234, createdAt: '2024-01-01T00:00:00Z'
};

const mockChannels = {
  'general': { id: 'ch-001', name: 'general', slug: 'general', serverId: 'server-001',
    type: 'TEXT', visibility: 'PUBLIC_INDEXABLE', topic: 'General discussion',
    description: null, position: 0, createdAt: '2024-01-01T00:00:00Z' },
  'announcements': { id: 'ch-002', name: 'announcements', slug: 'announcements', serverId: 'server-001',
    type: 'ANNOUNCEMENT', visibility: 'PUBLIC_NO_INDEX', topic: 'Official announcements',
    description: null, position: 1, createdAt: '2024-01-01T00:00:00Z' },
  'private-channel': { id: 'ch-003', name: 'private-channel', slug: 'private-channel', serverId: 'server-001',
    type: 'TEXT', visibility: 'PRIVATE', topic: null,
    description: null, position: 2, createdAt: '2024-01-01T00:00:00Z' },
};

const mockMessages = {
  'ch-001': { messages: [
    { id: 'msg-001', content: 'Welcome to Harmony! This is the first message.', createdAt: '2024-06-01T10:00:00Z', editedAt: null, author: { id: 'user-001', username: 'alice' } },
    { id: 'msg-002', content: 'Hello everyone! Excited to be here.', createdAt: '2024-06-01T10:05:00Z', editedAt: null, author: { id: 'user-002', username: 'bob' } },
    { id: 'msg-003', content: 'This is a public channel that search engines can index.', createdAt: '2024-06-01T10:10:00Z', editedAt: null, author: { id: 'user-001', username: 'alice' } },
  ], page: 1, pageSize: 50 },
  'ch-002': { messages: [
    { id: 'msg-010', content: 'Important announcement: Harmony v2.0 is live!', createdAt: '2024-06-15T09:00:00Z', editedAt: null, author: { id: 'user-001', username: 'alice' } },
  ], page: 1, pageSize: 50 },
};

const server = http.createServer((req, res) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Content-Type', 'application/json');

  const url = req.url || '/';
  console.log(`${req.method} ${url}`);

  // GET /api/public/servers/:serverSlug
  const serverMatch = url.match(/^\/api\/public\/servers\/([^\/]+)$/);
  if (serverMatch) {
    const slug = decodeURIComponent(serverMatch[1]);
    if (slug === 'harmony-hq') {
      res.setHeader('Cache-Control', 'public, max-age=300');
      res.writeHead(200);
      res.end(JSON.stringify(mockServer));
    } else {
      res.writeHead(404);
      res.end(JSON.stringify({ error: 'Server not found' }));
    }
    return;
  }

  // GET /api/public/servers/:serverSlug/channels/:channelSlug (single channel)
  const channelSlugMatch = url.match(/^\/api\/public\/servers\/([^\/]+)\/channels\/([^\/\?]+)(\?.*)?$/);
  if (channelSlugMatch) {
    const serverSlug = decodeURIComponent(channelSlugMatch[1]);
    const channelSlug = decodeURIComponent(channelSlugMatch[2]);
    if (serverSlug !== 'harmony-hq') {
      res.writeHead(404);
      res.end(JSON.stringify({ error: 'Server not found' }));
      return;
    }
    const channel = mockChannels[channelSlug];
    if (!channel) {
      res.writeHead(404);
      res.end(JSON.stringify({ error: 'Channel not found' }));
      return;
    }
    if (channel.visibility === 'PRIVATE') {
      res.writeHead(403);
      res.end(JSON.stringify({ error: 'Channel is private' }));
      return;
    }
    res.setHeader('Cache-Control', 'public, max-age=300');
    res.writeHead(200);
    res.end(JSON.stringify(channel));
    return;
  }

  // GET /api/public/channels/:channelId/messages
  const messagesMatch = url.match(/^\/api\/public\/channels\/([^\/]+)\/messages(\?.*)?$/);
  if (messagesMatch) {
    const channelId = decodeURIComponent(messagesMatch[1]);
    const data = mockMessages[channelId] || { messages: [], page: 1, pageSize: 50 };
    res.setHeader('Cache-Control', 'public, max-age=60');
    res.writeHead(200);
    res.end(JSON.stringify(data));
    return;
  }

  res.writeHead(404);
  res.end(JSON.stringify({ error: 'Not found' }));
});

server.listen(3001, () => {
  console.log('Mock API server running on http://localhost:3001');
});
